pure fn is_vowel(c: Text) -> Boolean {
    return c in ["a", "e", "i", "o", "u", "A", "E", "I", "O", "U"]
}

pure fn count_vowels(text: Text) -> Number {
    total = 0
    for c in split(text, "") {
        if is_vowel(c) {
            total = total + 1
        }
    }
    return total
}

entry main(input: Text) {
    return count_vowels("Programming is fun")
}

pure fn find_max(numbers: [Number]) -> Number {
    if length(numbers) == 0 { return 0 }
    current_max = get(numbers, 0)
    for n in numbers {
        if n > current_max {
            current_max = n
        }
    }
    return current_max
}

entry main(x: Text) {
    return find_max([34, 12, 89, 3, 56, 72])
}

