import summarize from "stdlib/language"

pure fn sum_list(numbers: [Number]) -> Number {
    total = 0
    for n in numbers {
        total = total + n
    }
    return total
}

entry main(x: Text) {
    amounts = [10.5, 20.3, 15.7]
    total = sum_list(amounts)
    summary = summarize(join(["Total spending: ", to_text(total), ". Amounts: ", to_text(amounts)], ""), 100)
    return join(["Total: ", to_text(total), ". Pattern: ", summary], "")
}

pure fn longest_word(text: Text) -> Text {
    words = split(text, " ")
    longest = ""
    for word in words {
        if length(word) > length(longest) {
            longest = word
        }
    }
    return longest
}

intent explain_meaning(word: Text) -> Text {
    goal: clear explanation of what word means
    constraints {
        explanation_is_concise_and_accessible
        uses_simple_language
    }
}

entry main(x: Text) {
    text = "extraordinary programming capabilities"
    word = longest_word(text)
    explanation = explain_meaning(word)
    return join(["Longest word: ", word, "\n\nMeaning: ", explanation], "")
}

intent extract_dates(text: Text) -> Text {
    goal: comma-separated ISO dates from text
    constraints {
        output_format_is_YYYY-MM-DD_comma_YYYY-MM-DD
        preserve_chronological_order
    }
    examples {
        ("Meeting: 2024-01-15, Deadline: 2024-02-28") => ("2024-01-15,2024-02-28")
    }
}

intent assess_timeline(days: Number) -> Text {
    goal: reasonable_or_unreasonable given days between dates
    constraints {
        consider_44_days_reasonable_for_project_timeline
        return_one_word_reasonable_or_tight_or_unreasonable
    }
}

pure fn parse_date_component(date: Text, position: Number) -> Number {
    parts = split(date, "-")
    return to_number(get(parts, position))
}

pure fn days_in_month(year: Number, month: Number) -> Number {
    if month == 2 {
        if year % 4 == 0 and (year % 100 != 0 or year % 400 == 0) {
            return 29
        }
        return 28
    }
    if month in [4, 6, 9, 11] { return 30 }
    return 31
}

pure fn calculate_days_between(date1: Text, date2: Text) -> Number {
    y1 = parse_date_component(date1, 0)
    m1 = parse_date_component(date1, 1)
    d1 = parse_date_component(date1, 2)
    y2 = parse_date_component(date2, 0)
    m2 = parse_date_component(date2, 1)
    d2 = parse_date_component(date2, 2)

    total = 0
    current_year = y1
    current_month = m1

    for i in range(0, 365 * 10) {
        if current_year == y2 and current_month == m2 {
            total = total + (d2 - d1)
            return total
        }
        days_this_month = days_in_month(current_year, current_month)
        if current_year == y1 and current_month == m1 {
            total = total + (days_this_month - d1)
        } else {
            total = total + days_this_month
        }
        current_month = current_month + 1
        if current_month > 12 {
            current_month = 1
            current_year = current_year + 1
        }
    }
    return total
}

entry main(x: Text) {
    dates_str = extract_dates("Meeting: 2024-01-15, Deadline: 2024-02-28")
    dates = split(dates_str, ",")
    date1 = get(dates, 0)
    date2 = get(dates, 1)
    days = calculate_days_between(date1, date2)
    assessment = assess_timeline(days)
    return join([to_text(days), " days - ", assessment], "")
}

pure fn count_char_frequencies(text: Text) -> {key: Number} {
    result = {}
    chars = split(lower(text), "")
    for c in chars {
        if c != " " {
            current = 0
            if c in result {
                current = result[c]
            }
            result[c] = current + 1
        }
    }
    return result
}

intent describe_pattern(frequencies: {key: Number}) -> Text {
    goal: natural language description of character frequency distribution
}

entry main(x: Text) {
    freqs = count_char_frequencies("hello world")
    description = describe_pattern(freqs)
    return description
}

pure fn sort_descending(nums: [Number]) -> [Number] {
    return reverse(sort(nums))
}

pure fn find_index(nums: [Number], target: Number) -> Number {
    for i in range(0, length(nums)) {
        if get(nums, i) == target {
            return i
        }
    }
    return -1
}

pure fn calculate_percentile(position: Number, total: Number) -> Number {
    return ((total - position) / total) * 100
}

intent explain_percentile(value: Number, percentile: Number, sorted_list: [Number]) -> Text {
    goal: Natural language explanation of what percentile the value falls in within the sorted list
}

entry main(x: Text) {
    nums = [42, 17, 8, 93, 55]
    sorted_nums = sort_descending(nums)
    position = find_index(sorted_nums, 42)
    percentile = calculate_percentile(position, length(sorted_nums))
    explanation = explain_percentile(42, percentile, sorted_nums)
    return join([to_text(sorted_nums), "\n", explanation], "")
}

import summarize from "stdlib/language"

pure fn parse_pairs(text: Text) -> [[Text]] {
    entries = split(text, ",")
    result = []
    for entry in entries {
        parts = split(entry, ":")
        result = append(result, parts)
    }
    return result
}

pure fn count_grade(pairs: [[Text]], target: Text) -> Number {
    count = 0
    for pair in pairs {
        grade = get(pair, 1)
        if grade == target { count = count + 1 }
    }
    return count
}

pure fn build_stats(pairs: [[Text]]) -> Text {
    a_count = count_grade(pairs, "A")
    total = length(pairs)
    return join(["Total students: ", to_text(total), ", Grade A count: ", to_text(a_count)], "")
}

entry main(x: Text) {
    pairs = parse_pairs("John:A,Jane:B,Jim:C,Jill:A")
    stats = build_stats(pairs)
    summary = summarize(stats, 50)
    return summary
}

pure fn mean(numbers: [Number]) -> Number {
    sum = 0
    for n in numbers {
        sum = sum + n
    }
    return sum / length(numbers)
}

pure fn variance(numbers: [Number]) -> Number {
    avg = mean(numbers)
    sum_sq_diff = 0
    for n in numbers {
        diff = n - avg
        sum_sq_diff = sum_sq_diff + (diff * diff)
    }
    return sum_sq_diff / length(numbers)
}

pure fn sqrt_approx(x: Number) -> Number {
    if x == 0 { return 0 }
    guess = x / 2
    for i in range(1, 11) {
        guess = (guess + x / guess) / 2
    }
    return guess
}

pure fn std_dev(numbers: [Number]) -> Number {
    return sqrt_approx(variance(numbers))
}

intent explain_variability(std_deviation: Number, data_range: Number) -> Text {
    goal: explain whether the data is highly variable given the standard deviation and range
    constraints {
        considers both absolute std_dev and relative to range
        provides clear yes or no assessment
    }
}

entry main(x: Text) {
    data = [10, 12, 23, 23, 16, 23, 21, 16]
    sd = std_dev(data)
    data_range = max(data) - min(data)
    explanation = explain_variability(sd, data_range)
    return join(["Standard deviation: ", to_text(sd), ". ", explanation], "")
}

pure fn reverse_text(s: Text) -> Text {
    chars = split(s, "")
    reversed = reverse(chars)
    return join(reversed, "")
}

pure fn reverse_words(text: Text) -> [Text] {
    words = split(text, " ")
