import extract from "stdlib/language"

pure fn is_valid_email(email: Text) -> Boolean {
    parts = split(email, "@")
    if length(parts) != 2 { return false }
    local = get(parts, 0)
    domain = get(parts, 1)
    if length(local) == 0 { return false }
    if length(domain) == 0 { return false }
    domain_parts = split(domain, ".")
    if length(domain_parts) < 2 { return false }
    return true
}

intent draft_greeting(email: Text) -> Text {
    goal: personalized greeting for email address
}

pure fn validate_and_greet(emails: [Text]) -> Text {
    results = []
    for email in emails {
        if is_valid_email(email) {
            greeting = draft_greeting(email)
            results = append(results, join([email, ": ", greeting], ""))
        }
    }
    return join(results, "\n")
}

entry main(x: Text) {
    text = "Contact alice@test.com or bob@test.com for info"
    extracted = extract(text, "list of email addresses")
    emails = split(extracted, " ")
    return validate_and_greet(emails)
}

pure fn compound_interest(principal: Number, rate: Number, years: Number) -> Number {
    return principal * ((1 + rate) * (1 + rate) * (1 + rate))
}

intent explain_to_teenager(amount: Number, original: Number, rate: Number, years: Number) -> Text {
    goal: explain compound interest result in teenager-friendly language
    constraints {
        use_simple_vocabulary
        mention_how_money_grew
        show_enthusiasm_appropriate_for_age
    }
}

entry main(x: Text) {
    principal = 1000
    rate = 0.05
    years = 3
    final_amount = compound_interest(principal, rate, years)
    explanation = explain_to_teenager(final_amount, principal, rate, years)
    return join([to_text(final_amount), "; ", explanation], "")
}

pure fn count_lines(text: Text) -> Number {
    return length(split(text, "."))
}

pure fn count_words(text: Text) -> Number {
    words = split(trim(text), " ")
    total = 0
    for word in words {
        if length(trim(word)) > 0 {
            total = total + 1
        }
    }
    return total
}

pure fn count_chars(text: Text) -> Number {
    return length(text)
}

intent rate_conciseness(text: Text, word_count: Number) -> Text {
    goal: classify as concise or verbose based on text content and word count
    constraints {
        result in ["concise", "verbose"]
    }
}

entry main(x: Text) {
    paragraph = "The sun was setting. Birds flew home. Silence fell."
    lines = count_lines(paragraph)
    words = count_words(paragraph)
    chars = count_chars(paragraph)
    rating = rate_conciseness(paragraph, words)
    return join(["Lines: ", to_text(lines), ", Words: ", to_text(words), ", Characters: ", to_text(chars), ", Rating: ", rating], "")
}

pure fn parse_city_lat(entry: Text) -> Text {
    parts = split(entry, ":")
    city = get(parts, 0)
    lat = to_number(get(parts, 1))
    return join([city, ":", to_text(lat)], "")
}

pure fn extract_lat(entry: Text) -> Number {
    parts = split(entry, ":")
    return to_number(get(parts, 1))
}

pure fn sort_by_latitude(entries: [Text]) -> [Text] {
    // Simple bubble sort by latitude
    sorted = entries
    n = length(sorted)
    for i in range(0, n) {
        for j in range(0, n - 1) {
            current = extract_lat(get(sorted, j))
            next = extract_lat(get(sorted, j + 1))
            if current > next {
                temp = get(sorted, j)
                sorted_j = get(sorted, j + 1)
                sorted_j1 = temp
                // Reconstruct list with swapped elements
                left = slice(sorted, 0, j)
                right = slice(sorted, j + 2, n)
                sorted = append(append(left, sorted_j), sorted_j1)
                sorted = append(sorted, right)
            }
        }
    }
    return sorted
}

intent describe_pattern(sorted_cities: Text) -> Text {
    goal: describe the geographic pattern of these cities from south to north
}

entry main(x: Text) {
    entries = split(x, ",")
    sorted_entries = sort_by_latitude(entries)
    formatted = join(sorted_entries, ", ")
    pattern = describe_pattern(formatted)
    return join([formatted, " - Pattern: ", pattern], "")
}

pure fn fibonacci(n: Number) -> Number {
    if n <= 1 { return n }
    return fibonacci(n - 1) + fibonacci(n - 2)
}

pure fn generate_fibonacci(count: Number) -> [Number] {
    results = []
    for i in range(0, count) {
        results = append(results, fibonacci(i))
    }
    return results
}

intent explain_golden_ratio(sequence: Text) -> Text {
    goal: explanation of why the golden ratio appears in the Fibonacci sequence
    constraints {
        mention the ratio of consecutive terms
        explain the convergence to phi
        keep explanation under 200 words
    }
}

entry main(x: Text) {
    fib_sequence = generate_fibonacci(8)
    sequence_text = join(map(fib_sequence, "to_text"), ", ")
    explanation = explain_golden_ratio(sequence_text)
    return join(["Fibonacci sequence: ", sequence_text, "\n\nExplanation: ", explanation], "")
}

pure fn is_stop_word(word: Text) -> Boolean {
    stop_words = ["the", "a", "an", "is", "in", "on", "at", "to"]
    return lower(word) in stop_words
}

pure fn remove_stop_words(text: Text) -> Text {
    words = split(text, " ")
    filtered = []
    for word in words {
        if not is_stop_word(word) {
            filtered = append(filtered, word)
        }
    }
    return join(filtered, " ")
}

intent summarize_text(text: Text) -> Text {
    goal: concise summary of the key content
}

entry main(x: Text) {
    input_text = "the cat is on the mat in the room"
    cleaned = remove_stop_words(input_text)
    return summarize_text(cleaned)
}
